module RefModule (
    input clk,
    input [3:0] A,
    input [3:0] B,
    output reg [3:0] result
);
    reg [3:0] obf_sum;

    // First stage: Addition
    always @(posedge clk) begin
        obf_sum <= A + B;
    end

    // Second stage: Modulo operation
    always @(posedge clk) begin
        result <= obf_sum % 16;
    end
endmodule
